script.inlineScript:
import { readFileSync, writeFileSync } from 'fs';

const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
const jobResult = input.steps?.['run-databricks-job'] || {};

writeFileSync('/output/result.json', JSON.stringify({
  verified: true,
  jobRunId: jobResult.runId,
  summary: `Databricks job completed. Output at: ${input.steps?.['configure-job']?.outputPath}`
}));

config.body:
The data processing job for dataset "${steps['configure-job'].datasetName}" has completed.

Output: ${steps['configure-job'].outputPath}
Job run: ${steps['run-databricks-job'].runId}
